<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;IC Mean&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: ic.mean(),</span></span>
